#include<bits/stdc++.h>
using namespace std;
int n,k;
int a[205],b[205],c[205],ans=1,maxx=0,dp[305][6005];
bool v[205];
int main(){
    cin>>n>>k;
    for(int i=1;i<=n;i++){
        int x;
        cin>>x;
        for(int j=2;x&&j<=3;j++){
            if(x%j==0){
                x/=j;
                if(j==2) a[i]++;
                else b[i]++;
                j--;

            }
        }
    }
    memset(dp,-1,sizeof(dp));
    dp[0][0]=0;
    for(int i=1;i<=n;i++){
        for (int j = k; j >= 1; --j) {
            for (int s2 = 6000; s2 >= a[i]; --s2) {
                if (dp[j-1][s2 - a[i]] != -1) {
                    dp[j][s2] = max(dp[j][s2], dp[j-1][s2 - a[i]] + b[i]);
                }
            }
        }
    }
     for (int s2 = 6000; s2 >= 0; --s2) if(dp[k][s2]!=-1) maxx=max(maxx,min(s2,dp[k][s2]));

    cout<<maxx;
    return 0;
}
